161→export async function buildApiError(response: Response): Promise<Error> {
162→  const text = await response.text();
163→  let detail = "";
164→
165→  try {
166→    const payload = JSON.parse(text) as { detail?: unknown };
167→    if (payload && "detail" in payload) {
168→      detail = stringifyDetail(payload.detail);
169→    }
170→  } catch {
171→    // Fallback to raw response text.
172→  }
173→
174→  const message = localizeApiMessage({
175→    status: response.status,
176→    detail,
177→    raw: text,
178→    isNetwork: false,
179→  });
180→  return new ApiClientError(message, { status: response.status, detail, raw: text });
181→}
