203→export async function request<T>(path: string, options: RequestOptions = {}): Promise<T> {
204→  const response = await safeFetch(`${API_BASE}${path}`, {
205→    method: options.method ?? "GET",
206→    headers: buildHeaders(options.token, options.demoUser),
207→    body: options.body === undefined ? undefined : JSON.stringify(options.body),
208→    cache: "no-store",
