1892→function resolveApiBase(): string {
1893→  const explicit = process.env.NEXT_PUBLIC_API_BASE_URL?.trim();
1894→  if (explicit) {
1895→    const base = explicit.replace(/\/+$/, "");
1896→    // If server-side (inside Docker) and targeting localhost, swap to internal "backend" service
1897→    if (typeof window === "undefined" && (base.includes("localhost") || base.includes("127.0.0.1"))) {
1898→      return base.replace(/localhost|127\.0\.0\.1/, "backend");
1899→    }
1900→    return base;
1901→  }
1902→
1903→  if (typeof window !== "undefined") {
1904→    const host = window.location.hostname.toLowerCase();
1905→    if (host === "localhost" || host === "127.0.0.1") {
1906→      return "http://localhost:8000";
1907→    }
1908→  }
1909→
1910→  // Handle server-side inference when no environment variable is set
1911→  if (typeof window === "undefined") {
1912→    return "http://backend:8000";
1913→  }
1914→
1915→  // Safety fallback for Railway production when NEXT_PUBLIC_API_BASE_URL is missing.
1916→  return "https://backend-production-0e53.up.railway.app";
1917→}
