1934→
1935→class ApiClientError extends Error {
1936→  status?: number;
1937→  detail?: string;
1938→  raw?: string;
1939→  isNetwork: boolean;
1940→
1941→  constructor(message: string, init: ApiClientErrorInit = {}) {
1942→    super(message);
1943→    this.name = "ApiClientError";
1944→    this.status = init.status;
1945→    this.detail = init.detail;
1946→    this.raw = init.raw;
1947→    this.isNetwork = Boolean(init.isNetwork);
1948→  }
1949→
1950→  override toString(): string {
1951→    return this.message;
1952→  }
1953→}
1954→
1955→function stringifyDetail(detail: unknown): string {
1956→  if (typeof detail === "string") {
1957→    return detail.trim();
1958→  }
1959→  if (Array.isArray(detail)) {
1960→    const parts = detail
1961→      .map((item) => {
1962→        if (typeof item === "string") return item.trim();
1963→        if (item && typeof item === "object") {
1964→          const record = item as Record<string, unknown>;
1965→          const msg = typeof record.msg === "string" ? record.msg.trim() : "";
1966→          const loc = Array.isArray(record.loc)
1967→            ? record.loc.map((chunk) => String(chunk)).join(".")
1968→            : "";
1969→          return [loc, msg].filter(Boolean).join(": ");
1970→        }
1971→        return "";
1972→      })
1973→      .filter(Boolean);
1974→    return parts.join("; ").trim();
1975→  }
1976→  if (detail && typeof detail === "object") {
1977→    const record = detail as Record<string, unknown>;
1978→    if (typeof record.message === "string" && record.message.trim()) {
1979→      return record.message.trim();
1980→    }
1981→    try {
1982→      return JSON.stringify(detail);
1983→    } catch {
1984→      return "";
1985→    }
1986→  }
1987→  return "";
1988→}
1989→
1990→function localizeApiMessage(params: {
1991→  status?: number;
1992→  detail?: string;
1993→  raw?: string;
1994→  isNetwork?: boolean;
1995→}): string {
1996→  const status = params.status;
1997→  const detail = (params.detail || "").trim();
1998→  const raw = (params.raw || "").trim();
1999→  const text = `${detail} ${raw}`.toLowerCase();
2000→
2001→  if (params.isNetwork) {
2002→    if (text.includes("iso-8859-1") || text.includes("headers") || text.includes("requestinit")) {
2003→      return "Помилка заголовків запиту. Перезавантаж сторінку і спробуй ще раз.";
2004→    }
2005→    return "Не вдалося підключитися до сервера. Перевір з'єднання або стан backend.";
2006→  }
2007→
2008→  if (text.includes("insufficient_quota") || text.includes("analysis limit reached") || status === 402) {
2009→    return "Ліміт тарифу або AI-квота вичерпано. Онови план або спробуй пізніше.";
2010→  }
2011→  if (text.includes("недостатньо тексту") || text.includes("not enough text")) {
2012→    return "Недостатньо тексту для аналізу документа. Додай більш змістовний файл.";
2013→  }
2014→  if (text.includes("incorrect email or password") || text.includes("невірний email") || text.includes("неправильний email")) {
2015→    return "Невірний email або пароль.";
2016→  }
2017→  if (text.includes("string contains non iso-8859-1 code point")) {
2018→    return "Запит містить неприпустимі символи в заголовках. Очисть сесію і повтори.";
2019→  }
2020→
2021→  if (status === 401) return "Сесія завершилась або недійсна. Увійди знову.";
2022→  if (status === 403) return "Немає доступу до цієї дії.";
2023→  if (status === 404) return "Ресурс не знайдено.";
2024→  if (status === 409) return "Конфлікт даних. Онови сторінку і повтори дію.";
2025→  if (status === 422) return detail || "Помилка валідації даних. Перевір поля форми.";
2026→  if (status === 429) return "Забагато запитів. Спробуй через хвилину.";
2027→  if (typeof status === "number" && status >= 500) return "Сервер тимчасово недоступний. Спробуй пізніше.";
2028→
2029→  if (detail) return detail;
2030→  if (raw) return raw;
2031→  if (status) return `API ${status}`;
2032→  return "Невідома помилка запиту.";
2033→}
