2035→function buildAuthHeaders(token?: string, demoUser?: string): Record<string, string> {
2036→  const headers: Record<string, string> = {};
2037→  const normalizedToken = token?.trim();
2038→  const normalizedDemoUser = demoUser?.trim();
2039→
2040→  if (normalizedToken) {
2041→    headers.Authorization = `Bearer ${normalizedToken}`;
2042→  }
2043→
2044→  // Demo header is only needed for unauthenticated/demo mode.
2045→  // Browsers reject non-Latin-1 header values, so never send user-entered names here.
2046→  if (!normalizedToken && normalizedDemoUser && /^[\x00-\x7F]+$/.test(normalizedDemoUser)) {
2047→    headers["X-Demo-User"] = normalizedDemoUser;
2048→  }
2049→  return headers;
2050→}
2051→
2052→function buildHeaders(token?: string, demoUser?: string): HeadersInit {
2053→  const headers = buildAuthHeaders(token, demoUser);
2054→  headers["Content-Type"] = "application/json";
2055→  return headers;
2056→}
