2058→async function buildApiError(response: Response): Promise<Error> {
2059→  const text = await response.text();
2060→  let detail = "";
2061→
2062→  try {
2063→    const payload = JSON.parse(text) as { detail?: unknown };
2064→    if (payload && "detail" in payload) {
2065→      detail = stringifyDetail(payload.detail);
2066→    }
2067→  } catch {
2068→    // Non-JSON response body, fallback to raw text.
2069→  }
2070→
2071→  const message = localizeApiMessage({
2072→    status: response.status,
2073→    detail,
2074→    raw: text,
2075→    isNetwork: false,
2076→  });
2077→  return new ApiClientError(message, { status: response.status, detail, raw: text });
2078→}
2079→
2080→function buildNetworkError(error: unknown): Error {
2081→  const raw = error instanceof Error ? error.message : String(error ?? "");
2082→  const message = localizeApiMessage({ raw, isNetwork: true });
2083→  return new ApiClientError(message, { raw, isNetwork: true });
2084→}
2085→
2086→async function safeFetch(input: string, init: RequestInit): Promise<Response> {
2087→  try {
2088→    return await fetch(input, init);
2089→  } catch (error) {
2090→    throw buildNetworkError(error);
2091→  }
2092→}
2093→
2094→export function getErrorMessage(error: unknown): string {
2095→  if (error instanceof Error) return error.message;
2096→  if (typeof error === "string" && error.trim()) return error.trim();
2097→  return "Невідома помилка.";
2098→}
2099→
2100→async function request<T>(path: string, options: RequestOptions = {}): Promise<T> {
2101→  const response = await safeFetch(`${API_BASE}${path}`, {
2102→    method: options.method ?? "GET",
2103→    headers: buildHeaders(options.token, options.demoUser),
2104→    body: options.body === undefined ? undefined : JSON.stringify(options.body),
2105→    cache: "no-store"
2106→  });
2107→
2108→  if (!response.ok) {
2109→    throw await buildApiError(response);
2110→  }
2111→  return (await response.json()) as T;
2112→}
