2524→export async function autoProcessDocument(
2525→  payload: {
2526→    file: File;
2527→    max_documents?: number;
2528→    processual_only?: boolean;
2529→  },
2530→  onEvent: (data: any) => void,
2531→  token?: string,
2532→  demoUser?: string
2533→): Promise<AutoProcessResponse> {
2534→  const form = new FormData();
2535→  form.append("file", payload.file);
2536→  if (payload.max_documents !== undefined) {
2537→    form.append("max_documents", String(payload.max_documents));
2538→  }
2539→  if (payload.processual_only !== undefined) {
2540→    form.append("processual_only", String(payload.processual_only));
2541→  }
2542→
2543→  const response = await safeFetch(`${API_BASE}/api/auto/process-stream`, {
2544→    method: "POST",
2545→    headers: buildAuthHeaders(token, demoUser),
2546→    body: form,
2547→    cache: "no-store"
2548→  });
2549→
2550→  if (!response.ok) {
2551→    throw await buildApiError(response);
2552→  }
2553→
2554→  if (!response.body) {
2555→    throw new ApiClientError("Сервер не повернув потік даних.", { raw: "No response body" });
2556→  }
2557→
2558→  const reader = response.body.getReader();
2559→  const decoder = new TextDecoder("utf-8");
2560→  let finalResult: AutoProcessResponse | null = null;
2561→  let buffer = "";
2562→
2563→  while (true) {
2564→    const { done, value } = await reader.read();
2565→    if (done) break;
2566→
2567→    buffer += decoder.decode(value, { stream: true });
2568→    const lines = buffer.split("\n");
2569→    buffer = lines.pop() || "";
2570→
2571→    for (const line of lines) {
2572→      if (line.startsWith("data: ")) {
2573→        const dataStr = line.slice(6).trim();
2574→        if (!dataStr) continue;
2575→        try {
2576→          const parsed = JSON.parse(dataStr);
2577→          onEvent(parsed);
2578→
2579→          if (parsed.step === "generation" && parsed.status === "done" && parsed.result) {
2580→            finalResult = parsed.result;
2581→          }
2582→        } catch (e) {
2583→          console.error("Failed to parse SSE JSON", e);
2584→        }
2585→      }
2586→    }
2587→  }
2588→
2589→  if (buffer.startsWith("data: ")) {
2590→    try {
2591→      const parsed = JSON.parse(buffer.slice(6).trim());
2592→      onEvent(parsed);
2593→      if (parsed.step === "generation" && parsed.status === "done" && parsed.result) {
2594→        finalResult = parsed.result;
2595→      }
2596→    } catch (e) {
2597→      // ignore
2598→    }
2599→  }
2600→
2601→  if (!finalResult) {
2602→    throw new ApiClientError("Потік завершився без фінального результату.", { raw: "Stream closed without final result." });
2603→  }
2604→
2605→  return finalResult;
2606→}
